const clean = (value) => String(value || '').replace(/<[^>]*>/g, '').replace(/&nbsp;/g, ' ').trim();
const original = clean($flow.state.route).toLowerCase() || 'general';
const human = clean($flow.state.needs_human).toLowerCase() === 'true';
const fullMenu = clean($flow.state.enviar_menu).toLowerCase() === 'true';
const config = clean($flow.state.configuracion_actual).toLowerCase();
const lastQuestion = clean($flow.state.ultima_pregunta_bot).toLowerCase();
const pendingConfig = !['', '{}', '[]', 'null', 'undefined'].includes(config);
const pendingOption = lastQuestion.startsWith('pedido_opcion:') || lastQuestion.startsWith('pedido_wafle_');
let route = original;
if (human || original === 'escalamiento') route = 'escalamiento';
else if (fullMenu) route = 'menu';
else if (pendingConfig || pendingOption) route = 'pedido';
return route;
